package ua.university.sms.model.entity;
import jakarta.persistence.*;import jakarta.validation.constraints.*;import java.util.*;
@Entity public class Teacher{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@NotBlank @Size(min=3,max=200) private String fullName;@Email @NotBlank @Column(unique=true) private String email;@NotBlank private String department;@OneToMany(mappedBy="teacher") private List<Course> courses=new ArrayList<>(); public Long getId(){return id;}public void setId(Long id){this.id=id;}public String getFullName(){return fullName;}public void setFullName(String fullName){this.fullName=fullName;}public String getEmail(){return email;}public void setEmail(String email){this.email=email;}public String getDepartment(){return department;}public void setDepartment(String department){this.department=department;}}
